<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand</title>
<style>
  *{margin:0;padding:0;box-sizing:border-box}
  body{background:#0d0d0d;color:#e0e0e0;font-family:'Segoe UI',Roboto,'Helvetica Neue',Arial,sans-serif;display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:100vh;padding:20px}
  h1{font-size:1.3rem;font-weight:300;letter-spacing:2px;text-transform:uppercase;margin-bottom:14px;color:#777}
  #controls{display:flex;gap:6px;margin-bottom:14px;flex-wrap:wrap;justify-content:center}
  button{background:#1e1e1e;color:#ccc;border:2px solid #333;border-radius:6px;padding:8px 16px;font-size:13px;font-weight:600;cursor:pointer;transition:all .12s ease;text-transform:uppercase;letter-spacing:.5px;user-select:none}
  button:hover{background:#2a2a2a;border-color:#555}
  button.active{border-color:#fff;box-shadow:0 0 10px rgba(255,255,255,.15);color:#fff}
  #mat-sand.active{border-color:#e6c229;color:#e6c229;box-shadow:0 0 10px rgba(230,194,41,.3)}
  #mat-water.active{border-color:#4a90d9;color:#4a90d9;box-shadow:0 0 10px rgba(74,144,217,.3)}
  #mat-wall.active{border-color:#888;color:#aaa;box-shadow:0 0 10px rgba(136,136,136,.3)}
  #mat-acid.active{border-color:#7fff00;color:#7fff00;box-shadow:0 0 10px rgba(127,255,0,.3)}
  #mat-empty.active{border-color:#ff4444;color:#ff4444;box-shadow:0 0 10px rgba(255,68,68,.3)}
  #clear{background:#2a1515;border-color:#4a2020;color:#ff6666}
  #clear:hover{background:#3a2020;border-color:#6a3030}
  #sand{border:2px solid #2a2a2a;border-radius:4px;cursor:crosshair;image-rendering:pixelated;box-shadow:0 4px 24px rgba(0,0,0,.6)}
</style>
</head>
<body>
<h1>Falling Sand</h1>
<div id="controls">
  <button id="mat-sand" class="active">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <button id="clear">Clear</button>
</div>
<canvas id="sand"></canvas>
<script>
(function(){
  'use strict';

  var W=200, H=200, CELL=2;
  var EMPTY=0, SAND=1, WATER=2, WALL=3, ACID=4;
  var NAMES=['empty','sand','water','wall','acid'];
  var COLORS=[
    [14,14,22],
    [230,194,41],
    [45,110,195],
    [85,85,105],
    [90,210,0]
  ];

  var grid=new Uint8Array(W*H);
  var moved=new Uint8Array(W*H);
  var selected=SAND;
  var painting=false;
  var lastX=-1, lastY=-1;

  var canvas=document.getElementById('sand');
  canvas.width=W*CELL;
  canvas.height=H*CELL;
  var ctx=canvas.getContext('2d');
  var imgData=ctx.createImageData(W*CELL, H*CELL);

  function idx(x,y){return y*W+x}

  /* ---- API ---- */
  window.sim={
    w:W,
    h:H,
    tick:function(n){
      for(var s=0;s<n;s++){
        moved.fill(0);
        for(var y=H-1;y>=0;y--){
          for(var x=0;x<W;x++){
            var i=idx(x,y);
            if(moved[i])continue;
            var m=grid[i];
            if(m===EMPTY||m===WALL)continue;
            if(m===SAND)updateSand(x,y,i);
            else if(m===WATER)updateWater(x,y,i);
            else if(m===ACID)updateAcid(x,y,i);
          }
        }
      }
    },
    get:function(x,y){
      if(x<0||x>=W||y<0||y>=H)return'wall';
      return NAMES[grid[idx(x,y)]];
    },
    set:function(x,y,material){
      if(x<0||x>=W||y<0||y>=H)return;
      var v=NAMES.indexOf(material);
      if(v>=0)grid[idx(x,y)]=v;
    },
    clear:function(){grid.fill(EMPTY)}
  };

  /* ---- Simulation ---- */
  function updateSand(x,y,i){
    if(y+1>=H)return;
    var b=idx(x,y+1), bm=grid[b];
    if(bm===EMPTY){grid[b]=SAND;grid[i]=EMPTY;moved[b]=1;moved[i]=1;return}
    if(bm===WATER||bm===ACID){grid[b]=SAND;grid[i]=bm;moved[b]=1;moved[i]=1;return}
    var dir=Math.random()<.5?-1:1;
    for(var k=0;k<2;k++){
      var d=[dir,-dir][k], nx=x+d;
      if(nx<0||nx>=W)continue;
      var ni=idx(nx,y+1), nm=grid[ni];
      if(nm===EMPTY){grid[ni]=SAND;grid[i]=EMPTY;moved[ni]=1;moved[i]=1;return}
      if(nm===WATER||nm===ACID){grid[ni]=SAND;grid[i]=nm;moved[ni]=1;moved[i]=1;return}
    }
  }

  function updateWater(x,y,i){
    if(y+1<H){
      var b=idx(x,y+1), bm=grid[b];
      if(bm===EMPTY){grid[b]=WATER;grid[i]=EMPTY;moved[b]=1;moved[i]=1;return}
    }
    var dir=Math.random()<.5?-1:1;
    for(var k=0;k<2;k++){
      var d=[dir,-dir][k], nx=x+d;
      if(nx<0||nx>=W||y+1>=H)continue;
      var ni=idx(nx,y+1);
      if(grid[ni]===EMPTY){grid[ni]=WATER;grid[i]=EMPTY;moved[ni]=1;moved[i]=1;return}
    }
    var hDir=Math.random()<.5?-1:1;
    for(var k2=0;k2<2;k2++){
      var hd=[hDir,-hDir][k2], nxx=x+hd;
      if(nxx<0||nxx>=W)continue;
      var nni=idx(nxx,y);
      if(grid[nni]===EMPTY){grid[nni]=WATER;grid[i]=EMPTY;moved[nni]=1;moved[i]=1;return}
    }
  }

  function updateAcid(x,y,i){
    var targets=[];
    if(y+1<H){
      var bm=grid[idx(x,y+1)];
      if(bm===SAND||bm===WALL)targets.push(idx(x,y+1));
    }
    for(var d=-1;d<=1;d+=2){
      var nx=x+d;
      if(nx>=0&&nx<W){
        var sm=grid[idx(nx,y)];
        if(sm===SAND||sm===WALL)targets.push(idx(nx,y));
      }
    }
    if(targets.length>0){
      var t=targets[Math.floor(Math.random()*targets.length)];
      grid[t]=EMPTY;
    }
    updateWater(x,y,i);
  }

  /* ---- Rendering ---- */
  function render(){
    var data=imgData.data;
    var cw=W*CELL;
    for(var y=0;y<H;y++){
      for(var x=0;x<W;x++){
        var m=grid[idx(x,y)];
        var c=COLORS[m];
        var v=((x*7+y*13)%16)-8;
        var r=Math.max(0,Math.min(255,c[0]+v));
        var g=Math.max(0,Math.min(255,c[1]+v));
        var b=Math.max(0,Math.min(255,c[2]+v));
        for(var cy=0;cy<CELL;cy++){
          for(var cx=0;cx<CELL;cx++){
            var px=x*CELL+cx, py=y*CELL+cy;
            var pi=(py*cw+px)*4;
            data[pi]=r;data[pi+1]=g;data[pi+2]=b;data[pi+3]=255;
          }
        }
      }
    }
    ctx.putImageData(imgData,0,0);
  }

  /* ---- Animation ---- */
  function loop(){
    window.sim.tick(1);
    render();
    requestAnimationFrame(loop);
  }

  /* ---- Input ---- */
  function getGridPos(e){
    var rect=canvas.getBoundingClientRect();
    var sx=(W*CELL)/rect.width;
    var sy=(H*CELL)/rect.height;
    return{x:Math.floor((e.clientX-rect.left)*sx/CELL),y:Math.floor((e.clientY-rect.top)*sy/CELL)};
  }

  function paint(x,y){
    var r=3;
    for(var dy=-r;dy<=r;dy++){
      for(var dx=-r;dx<=r;dx++){
        var nx=x+dx, ny=y+dy;
        if(nx>=0&&nx<W&&ny>=0&&ny<H)grid[idx(nx,ny)]=selected;
      }
    }
  }

  canvas.addEventListener('mousedown',function(e){
    e.preventDefault();
    painting=true;
    var p=getGridPos(e);
    lastX=p.x;lastY=p.y;
    paint(p.x,p.y);
  });
  canvas.addEventListener('mousemove',function(e){
    if(!painting)return;
    var p=getGridPos(e);
    var dx=p.x-lastX, dy=p.y-lastY;
    var dist=Math.max(Math.abs(dx),Math.abs(dy));
    var steps=Math.max(1,dist);
    for(var s=0;s<=steps;s++){
      var t=steps===0?0:s/steps;
      paint(Math.round(lastX+dx*t),Math.round(lastY+dy*t));
    }
    lastX=p.x;lastY=p.y;
  });
  canvas.addEventListener('mouseup',function(){painting=false});
  canvas.addEventListener('mouseleave',function(){painting=false});

  /* ---- Buttons ---- */
  document.querySelectorAll('#controls button:not(#clear)').forEach(function(btn){
    btn.addEventListener('click',function(){
      document.querySelectorAll('#controls button:not(#clear)').forEach(function(b){b.classList.remove('active')});
      btn.classList.add('active');
      selected=NAMES.indexOf(btn.id.replace('mat-',''));
    });
  });
  document.getElementById('clear').addEventListener('click',function(){window.sim.clear()});

  /* ---- Start ---- */
  loop();
})();
</script>
</body>
</html>
